fn solve(n: i64) -> String {
    fn convert_to_base(num: i64, base: u32) -> String {
        if num == 0 {
            return "0".to_string();
        }
        let mut result = String::new();
        let mut num = num;
        while num > 0 {
            let remainder = num % (base as i64);
            let char = if remainder < 10 {
                remainder.to_string()
            } else {
                let c = (b'A' + (remainder - 10)) as char;
                c.to_string()
            };
            result = format!("{}{}", char, result);
            num = num / (base as i64);
        }
        result
    }

    let n2 = n * n;
    let n3 = n2 * n;

    let hex = convert_to_base(n2, 16);
    let base36 = convert_to_base(n3, 36);

    format!("{}{}", hex, base36)
}
